namespace sv_bfa190bd77ae48d0afa8bdcd041ff161.Services;

/// <summary>
/// Adds a random notification every 15 seconds while active.
/// Scoped per circuit — activated/deactivated by the dashboard page.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly string[] Titles =
    [
        "CPU spike detected",
        "Disk usage warning",
        "New deployment ready",
        "Service health check failed",
        "Security patch available",
        "Database backup completed",
        "Memory threshold exceeded"
    ];

    private static readonly string[] Messages =
    [
        "Investigate immediately.",
        "Review the dashboard metrics.",
        "Acknowledge and schedule maintenance.",
        "No action required at this time.",
        "Escalate to the on-call team."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _cts = null;
        _timer = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct)) break;
            }
            catch (OperationCanceledException) { break; }

            var rand = Random.Shared;
            var title = Titles[rand.Next(Titles.Length)];
            var message = Messages[rand.Next(Messages.Length)];
            var severity = (Severity)rand.Next(3);

            _hub.AddNotification(title, message, severity);
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

