        {
            _notifications = Hub.Notifications;
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);
    private void Dismiss(Guid id) => Hub.DismissNotification(id);
    private void MarkAllRead() => Hub.MarkAllRead();

