@page "/dashboard"
@using sv_bfa190bd77ae48d0afa8bdcd041ff161.Services
@inject NotificationHub Hub
@inject SimulatorService Simulator
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h2>Dashboard</h2>

<NotificationSummaryPanel />

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

@using sv_bfa190bd77ae48d0afa8bdcd041ff161.Services
@inject NotificationHub Hub
@implements IDisposable

<div class="card mt-3">
    <div class="card-header">
        <strong>Recent Unread Notifications</strong>
    </div>
    <div class="card-body">
        @if (!_recent.Any())
        {
            <p class="text-muted mb-0">No unread notifications.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var n in _recent)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-center">
                        <div>
                            <span class="badge @GetBadgeClass(n.Severity) me-2">@n.Severity</span>
                            <strong>@n.Title</strong>
                            <small class="text-muted ms-2">@n.Timestamp.ToString("t")</small>
                        </div>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

@code {
    private List<Notification> _recent = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        RefreshRecent();
        _handler = () => InvokeAsync(() =>
        {
            RefreshRecent();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void RefreshRecent()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private static string GetBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

